mapper.select:
SELECT AVG(avg_elapsed_seconds)
FROM ${aggTable}
WHERE collected_at BETWEEN #{startTime} AND #{endTime}

    AND database_id = #{databaseId}

SELECT AVG(max_elapsed_seconds)
FROM ${aggTable}
WHERE collected_at BETWEEN #{startTime} AND #{endTime}

    AND database_id = #{databaseId}

SELECT SUM(total_dead_tuples)
FROM ${aggTable}
WHERE collected_at BETWEEN #{startTime} AND #{endTime}

    AND database_id = #{databaseId}

WITH time_series AS ( SELECT collected_at, total_dead_tuples, active_vacuum_sessions, avg_progress, LAG(total_dead_tuples) OVER (ORDER BY collected_at) as prev_dead_tuples, LAG(collected_at) OVER (ORDER BY collected_at) as prev_collected_at FROM ${aggTable} WHERE collected_at BETWEEN #{startTime} AND #{endTime}
AND database_id = #{databaseId}
), calculated AS ( SELECT DATE_TRUNC('hour', collected_at) as hour_bucket, CASE WHEN prev_dead_tuples IS NOT NULL AND prev_collected_at IS NOT NULL THEN (total_dead_tuples - prev_dead_tuples) / EXTRACT(EPOCH FROM (collected_at - prev_collected_at)) * 60 ELSE 0 END as increase_rate, active_vacuum_sessions * COALESCE(avg_progress, 0) / 100.0 as processing_rate FROM time_series ) SELECT TO_CHAR(hour_bucket, 'HH24:00') as hourLabel, AVG(increase_rate) as deadTupleIncreaseRate, AVG(processing_rate) as avgProgress FROM calculated GROUP BY hour_bucket ORDER BY hour_bucket LIMIT #{buckets}

SELECT
TO_CHAR(DATE_TRUNC('hour', collected_at), 'HH24:00') as hourLabel,
-- Cost Delay는 elapsed_seconds로 근사 (ms 단위)
AVG(avg_elapsed_seconds * 1000) as avgCostDelayMs,
-- Active Autovacuum Workers
AVG(autovacuum_sessions) as activeWorkers
FROM ${aggTable}
WHERE collected_at BETWEEN #{startTime} AND #{endTime}

    AND database_id = #{databaseId}

GROUP BY DATE_TRUNC('hour', collected_at)
ORDER BY DATE_TRUNC('hour', collected_at)
LIMIT #{buckets}

SELECT
TO_CHAR(DATE_TRUNC('hour', collected_at), 'HH24:00') as hourLabel,
AVG(avg_elapsed_seconds) as avgDelaySeconds
FROM ${aggTable}
WHERE collected_at BETWEEN #{startTime} AND #{endTime}

    AND database_id = #{databaseId}

GROUP BY DATE_TRUNC('hour', collected_at)
ORDER BY DATE_TRUNC('hour', collected_at)
LIMIT #{buckets}
